```python
def tanh(x):
    return np.tanh(x)  # or (np.exp(x) - np.exp(-x)) / (np.exp(x) + np.exp(-x))
```

---

```python
def relu(x):
    return np.maximum(0, x)
```

```python
def softmax(x):
    exp_x = np.exp(x - np.max(x))  # Subtract max for numerical stability
    return exp_x / np.sum(exp_x)
```

